insert into posts (id, category, category_label, tag, title, excerpt, content, icon, video, duration, views, comments, date, popular, rank) values
('info-004', 'info', '축구 정보', '선수 분석', '손흥민 폼 완벽 분석, 무엇이 다른가', '최근 5경기 활동량과 슈팅 패턴을 데이터로 뜯어봤다. 전문가들이 주목한 변화 포인트는 따로 있었다.', ARRAY['최근 5경기에서 손흥민의 평균 활동량은 시즌 초 대비 소폭 증가했다. 특히 오프더볼 움직임에서 상대 수비 라인 사이 공간을 파고드는 빈도가 눈에 띄게 늘었다는 분석이 나온다.','슈팅 패턴 데이터를 보면 페널티 박스 바깥에서의 시도 비중이 줄고, 박스 안쪽 왼발 마무리 비중이 높아졌다. 전문가들은 이를 골 결정력 향상의 핵심 변화로 꼽는다.','다음 경기에서도 이 흐름이 이어질지, 상대 수비 전술에 따라 얼마나 달라질지가 관전 포인트다.']::text[], 'ball', true, '8분', 15200, 128, '2026-07-18', true, 1),
('info-001', 'info', '축구 정보', '이적시장', '여름 이적시장 막바지, 남은 대형 매물 정리', '마감까지 3일, 아직 거취가 정해지지 않은 대형 이적 후보들을 포지션별로 정리했다.', ARRAY['이적시장 마감이 임박하면서 여러 구단이 막바지 협상에 속도를 내고 있다. 미드필더 자원을 중심으로 여러 팀이 동시에 관심을 보이는 상황이다.','포지션별로 보면 중앙 수비수와 측면 공격수 쪽 움직임이 가장 활발하며, 일부는 임대 형태로 마무리될 가능성도 제기된다.']::text[], 'chart', false, NULL, 8200, 34, '2026-07-19', false, NULL),
('info-002', 'info', '축구 정보', '경기 요약', '어젯밤 하이라이트, 3분 요약으로 보기', '놓친 경기가 있다면 이것만 보면 된다. 핵심 장면만 골라 3분 안에 정리했다.', ARRAY['어젯밤 열린 주요 경기들의 핵심 장면을 모았다. 득점 장면과 결정적인 수비 상황 위주로 편집해 짧은 시간에 전체 흐름을 파악할 수 있다.']::text[], 'video', true, '3분', 6500, 12, '2026-07-19', false, NULL),
('info-003', 'info', '축구 정보', 'SNS 화제', '연습 영상 하나로 화제가 된 유망주', '개인 SNS에 올린 훈련 영상 하나가 순식간에 퍼지며 스카우트들의 관심을 받고 있다.', ARRAY['한 유망주가 개인 계정에 올린 훈련 영상이 큰 화제를 모으고 있다. 짧은 영상이지만 볼 컨트롤과 판단 속도에서 또래 대비 확실한 차이를 보여준다는 평가다.']::text[], 'person', false, NULL, 5100, 21, '2026-07-17', false, NULL),
('info-005', 'info', '축구 정보', '이적시장', '이적시장 마감 D-3, 미드필더 영입설 확산', '여러 구단이 동시에 관심을 보이는 미드필더를 둘러싸고 영입설이 빠르게 퍼지고 있다.', ARRAY['마감을 사흘 앞두고 미드필더 한 명을 둘러싼 영입설이 확산되고 있다. 복수의 구단이 동시에 접촉했다는 보도가 나오며 최종 행선지에 관심이 쏠린다.']::text[], 'chart', false, NULL, 4300, 9, '2026-07-19', false, NULL),
('dribble-004', 'dribble', '드리블 훈련', '기초', '초보자를 위한 라보나 드리블 완전정복', '화려해 보이지만 원리는 단순하다. 라보나 드리블의 기본 스텝부터 실전 타이밍까지 순서대로 알아본다.', ARRAY['라보나 드리블은 다리를 교차해 공을 감아 차는 동작으로, 처음에는 스텝 타이밍을 익히는 것이 가장 중요하다.','제자리에서 스텝만 반복하는 연습으로 시작해, 익숙해지면 낮은 속도로 실제 볼 터치를 붙여본다.','실전에서는 상대가 예측하기 어려운 타이밍에 시도해야 효과가 크다.']::text[], 'boot', true, '5분', 9400, 41, '2026-07-18', true, 2),
('dribble-001', 'dribble', '드리블 훈련', '기초', '공을 몸에 붙이는 첫걸음, 터치 훈련', '드리블의 시작은 터치다. 공을 몸 가까이 두는 감각을 만드는 기초 루틴을 소개한다.', ARRAY['드리블의 완성도는 결국 볼 터치의 정교함에서 나온다. 이번 루틴은 제자리 터치부터 전진 터치까지 단계별로 구성됐다.']::text[], 'boot', true, '3분', 4300, 15, '2026-07-15', false, NULL),
('dribble-002', 'dribble', '드리블 훈련', '방향전환', '수비를 벗기는 크루이프 턴 완전분석', '각도, 무게중심, 타이밍까지. 크루이프 턴을 실전에서 통하게 만드는 디테일을 짚었다.', ARRAY['크루이프 턴은 단순해 보이지만 무게중심 이동과 발목 각도가 어긋나면 바로 볼을 빼앗긴다. 핵심 디테일을 단계별로 짚어본다.']::text[], 'zigzag', true, '5분', 9700, 38, '2026-07-16', false, NULL),
('dribble-003', 'dribble', '드리블 훈련', '실전응용', '좁은 공간에서 쓰는 엘라스티코 타이밍', '공간이 없을 때일수록 타이밍이 전부다. 좁은 공간에서 통하는 엘라스티코 사용법.', ARRAY['엘라스티코는 넓은 공간보다 오히려 좁은 공간에서 더 위력적이다. 상대와의 거리, 접촉 타이밍을 중심으로 정리했다.']::text[], 'ball', true, '4분', 7100, 19, '2026-07-14', false, NULL),
('dribble-005', 'dribble', '드리블 훈련', '유소년 연계', '초등부 드리블 훈련 루틴, 왜 효과적인가', '조회수 12만을 넘긴 화제의 루틴, 무엇이 다른지 코치의 설명을 들어봤다.', ARRAY['이 루틴이 화제가 된 이유는 단순함에 있다. 짧은 동작을 반복하되 매 세트마다 미세하게 난이도를 높이는 구성이 핵심이다.']::text[], 'boot', false, NULL, 12000, 52, '2026-07-19', false, NULL),
('skills-001', 'skills', '축구 스킬', '패스', '원터치 패스 정확도를 올리는 법', '생각보다 발끝이 아니라 몸의 방향이 정확도를 결정한다.', ARRAY['원터치 패스의 정확도는 임팩트 순간의 발끝 각도보다 패스 전 몸의 방향 설정에서 대부분 결정된다.']::text[], 'ball', false, NULL, 3800, 7, '2026-07-13', false, NULL),
('skills-002', 'skills', '축구 스킬', '프리킥', '프리킥 감아차기, 각도별 훈련법', '거리와 각도에 따라 달라지는 감아차기 임팩트 포인트를 정리했다.', ARRAY['프리킥 감아차기는 거리와 각도에 따라 임팩트 지점이 달라진다. 세 가지 거리대별로 훈련법을 나눠 설명한다.']::text[], 'zigzag', true, '6분', 6200, 24, '2026-07-12', false, NULL),
('skills-003', 'skills', '축구 스킬', '헤더', '헤더 타이밍 잡는 3가지 드릴', '높이보다 타이밍. 헤더 정확도를 올리는 실전 드릴 3가지.', ARRAY['헤더는 점프 높이보다 타이밍이 승부를 가른다. 실전에서 바로 적용 가능한 드릴 세 가지를 소개한다.']::text[], 'person', false, NULL, 4100, 11, '2026-07-11', false, NULL),
('skills-004', 'skills', '축구 스킬', '응용', '압박 상황에서 턴 활용하는 법', '압박이 들어오는 타이밍에 턴을 쓰는 판단 기준을 정리했다.', ARRAY['압박 상황에서의 턴은 타이밍보다 판단이 먼저다. 언제 턴을 시도하고 언제 내줘야 하는지 기준을 정리했다.']::text[], 'boot', true, '4분', 5300, 16, '2026-07-10', false, NULL),
('skills-005', 'skills', '축구 스킬', '밸런스', '왼발 감각 깨우는 5분 루틴', '매일 5분이면 충분하다. 약발 감각을 끌어올리는 루틴.', ARRAY['약발 감각은 짧고 꾸준한 반복이 가장 효과적이다. 매일 5분씩 실천 가능한 루틴으로 구성했다.']::text[], 'ball', true, '5분', 4700, 13, '2026-07-09', false, NULL),
('youth-004', 'youth', '유소년 축구', '가이드', '유소년 클럽 등록 전 꼭 확인할 5가지', '등록 전에 놓치기 쉬운 부분들을 학부모 관점에서 체크리스트로 정리했다.', ARRAY['유소년 클럽 등록을 앞두고 있다면 지도자 자격, 훈련 강도, 이동 거리, 비용 구조, 대회 참가 빈도 다섯 가지를 먼저 확인하는 것이 좋다.']::text[], 'person', false, NULL, 6100, 27, '2026-07-17', true, 4),
('youth-001', 'youth', '유소년 축구', '인터뷰', '그라운드 키즈 인터뷰, 부모가 알아야 할 것', '현직 유소년 지도자가 말하는, 부모가 흔히 오해하는 부분들.', ARRAY['현직 지도자는 부모가 결과보다 과정에 집중해야 아이가 더 오래 즐길 수 있다고 강조했다.']::text[], 'person', true, '7분', 3900, 18, '2026-07-08', false, NULL),
('youth-002', 'youth', '유소년 축구', '대회 준비', '초등부 대회 참가 준비물 체크리스트', '빠뜨리기 쉬운 준비물까지 한 번에 정리했다.', ARRAY['대회 당일 급하게 챙기다 놓치기 쉬운 물품들을 포함해 준비물을 체크리스트로 정리했다.']::text[], 'chart', false, NULL, 3300, 6, '2026-07-07', false, NULL),
('youth-003', 'youth', '유소년 축구', '부상 예방', '성장기 부상 예방을 위한 스트레칭', '성장통과 부상을 혼동하지 않으려면 알아야 할 스트레칭 습관.', ARRAY['성장기에는 근육과 뼈의 성장 속도 차이로 부상 위험이 커진다. 훈련 전후 스트레칭 습관을 짚어본다.']::text[], 'person', true, '4분', 4800, 14, '2026-07-06', false, NULL),
('youth-005', 'youth', '유소년 축구', '훈련', '유소년 지도자가 뽑은 필수 훈련 3가지', '현장에서 가장 많이 쓰이는 기본기 훈련 3가지를 물었다.', ARRAY['여러 유소년 지도자에게 물은 결과, 볼 터치·방향 전환·짧은 패스 세 가지가 가장 자주 언급됐다.']::text[], 'boot', false, NULL, 4000, 10, '2026-07-05', false, NULL),
('review-004', 'review', '축구화 리뷰', '리뷰', '풋살화 vs 축구화, 구장별 선택 가이드', '인조잔디, 천연잔디, 실내 코트까지. 구장 환경별로 맞는 신발을 정리했다.', ARRAY['풋살화와 축구화는 밑창 구조부터 다르다. 구장 환경에 맞지 않는 신발을 신으면 접지력이 떨어지고 부상 위험도 커진다.','인조잔디에는 AG 스터드, 천연잔디에는 FG 스터드, 실내 코트에는 IC 밑창이 기본이다.']::text[], 'boot', false, NULL, 7800, 33, '2026-07-18', true, 3),
('review-001', 'review', '축구화 리뷰', '착화감', '신형 축구화 착화감 비교, 어떤 게 나에게 맞을까', '발볼, 무게, 쿠셔닝까지 직접 신어보고 비교했다.', ARRAY['최근 출시된 모델들을 발볼 넓이와 무게, 쿠셔닝 기준으로 직접 비교했다.']::text[], 'boot', false, NULL, 5600, 22, '2026-07-04', false, NULL),
('review-002', 'review', '축구화 리뷰', '추천', '인조잔디용 축구화 추천 TOP 3', 'AG 스터드 모델 중 접지력과 내구성이 좋은 세 가지를 골랐다.', ARRAY['인조잔디 구장에서 많이 쓰이는 AG 스터드 모델 중 접지력과 내구성을 기준으로 세 모델을 선정했다.']::text[], 'boot', false, NULL, 4900, 17, '2026-07-03', false, NULL),
('review-003', 'review', '축구화 리뷰', '가이드', '축구화 사이즈 선택, 발볼 넓은 사람을 위한 팁', '발볼이 넓다면 이 기준부터 확인하자.', ARRAY['발볼이 넓은 편이라면 브랜드별 라스트(신발 골) 차이부터 확인하는 것이 먼저다.']::text[], 'boot', false, NULL, 3700, 9, '2026-07-02', false, NULL),
('review-005', 'review', '축구화 리뷰', '가성비', '가성비 축구화 3만원대 vs 10만원대 비교', '가격 차이가 실제 성능 차이로 이어지는지 직접 확인해봤다.', ARRAY['가격대별로 소재, 스터드 구조, 내구성을 비교한 결과 가격 차이가 곧바로 체감 성능 차이로 이어지지는 않았다.']::text[], 'boot', false, NULL, 4200, 15, '2026-07-01', false, NULL),
('ranking-001', 'ranking', '유튜브 랭킹', '랭킹', '이번 주 급상승 축구 유튜브 채널 TOP 5 공개', '구독자 증가율 기준으로 뽑은 이번 주 급상승 채널 5곳.', ARRAY['이번 주 구독자 증가율이 가장 높았던 채널 5곳을 정리했다. 드리블 훈련 콘텐츠를 다루는 채널들의 강세가 눈에 띈다.']::text[], 'video', true, '6분', 5500, 20, '2026-07-19', true, 5),
('ranking-002', 'ranking', '유튜브 랭킹', '채널 분석', '구독자 100만 눈앞, 풋볼튜토리얼의 비결', '1위 채널이 꾸준히 성장할 수 있었던 콘텐츠 전략을 분석했다.', ARRAY['풋볼튜토리얼은 짧은 드릴 영상과 긴 분석 영상을 병행하는 전략으로 꾸준한 성장세를 이어가고 있다.']::text[], 'video', false, NULL, 3600, 8, '2026-06-30', false, NULL),
('ranking-003', 'ranking', '유튜브 랭킹', '채널 분석', '축구화 리뷰 채널이 뜨는 이유', '리뷰 콘텐츠 카테고리가 최근 빠르게 성장하고 있다.', ARRAY['축구화 리뷰 콘텐츠는 구매 결정과 직결되는 정보라는 점에서 시청 완료율이 특히 높게 나타난다.']::text[], 'chart', false, NULL, 2900, 5, '2026-06-29', false, NULL);
